:root{
 --bg-shell:#eef2f7;
 --bg-panel:#ffffff;
 --bg-panel-muted:#f8fafc;
 --border-soft:#d0d5dd;
 --border-strong:#98a2b3;
 --text-strong:#101828;
 --text-body:#344054;
 --text-muted:#667085;
 --brand:#175cd3;
 --brand-deep:#0f3d91;
 --danger:#b42318;
 --danger-soft:#fef3f2;
 --danger-border:#fecdca;
 --warning:#b54708;
 --warning-soft:#fffaeb;
 --warning-border:#fedf89;
 --success:#027a48;
 --success-soft:#ecfdf3;
 --success-border:#abefc6;
 --shadow-soft:0 20px 40px rgba(15, 23, 42, 0.08);
}

body{
 font-family:"Segoe UI", "Helvetica Neue", Arial, sans-serif;
 background:
  radial-gradient(circle at top left, rgba(23, 92, 211, 0.08), transparent 30%),
  linear-gradient(180deg, #f8fbff 0%, var(--bg-shell) 48%, #e9eef5 100%);
 margin:0;
 padding:0;
 display:flex;
 justify-content:center;
 align-items:center;
 height:100vh;
}

body.exam-page{
 display:block;
 height:auto;
 min-height:100vh;
 overflow-y:auto;
 padding:24px 0;
}

.container{
 background:white;
 padding:40px;
 border-radius:10px;
 box-shadow:0 4px 10px rgba(0,0,0,0.1);
 width:400px;
 text-align:center;
}

h2{
 margin-bottom:20px;
}

input{
 width:90%;
 padding:10px;
 margin:10px 0;
 border-radius:5px;
 border:1px solid #ccc;
}

button{
 background:#007bff;
 color:white;
 border:none;
 padding:10px 20px;
 border-radius:5px;
 cursor:pointer;
}

button:hover{
 background:#0056b3;
}

button:disabled{
 background:#7aa7e0;
 cursor:not-allowed;
}

.status-message{
 min-height:24px;
 margin:0 auto;
 width:100%;
 font-size:14px;
 font-weight:600;
 padding:12px 14px;
 border-radius:12px;
 background:#eff8ff;
 border:1px solid #b2ddff;
 color:#175cd3;
}

.status-message.error{
 color:#b42318;
 background:#fef3f2;
 border-color:#fecdca;
}

.status-message.info{
 color:#175cd3;
 background:#eff8ff;
 border-color:#b2ddff;
}

/* dashboard */

.dashboard{
 text-align:center;
}

.dashboard-header{
 display:flex;
 justify-content:space-between;
 align-items:center;
 gap:16px;
}

.dashboard-card{
 background:#f7f9fc;
 border:1px solid #dfe6ef;
 border-radius:10px;
 padding:18px;
 margin:16px 0 24px;
 text-align:left;
}

.start-btn{
 background:#28a745;
 font-size:18px;
 padding:12px 30px;
}

.start-btn:hover{
 background:#1e7e34;
}

.modal-overlay{
 position:fixed;
 inset:0;
 background:rgba(15, 23, 42, 0.7);
 display:flex;
 align-items:center;
 justify-content:center;
 padding:24px;
 z-index:1000;
}

.modal-overlay[hidden]{
 display:none;
}

.modal-card{
 width:min(680px, 100%);
 max-height:85vh;
 overflow:auto;
 background:white;
 border-radius:14px;
 padding:28px;
 box-shadow:0 20px 40px rgba(15, 23, 42, 0.24);
 text-align:left;
}

.modal-card h3{
 margin:0 0 12px;
}

.modal-copy{
 margin:0 0 16px;
 color:#344054;
 line-height:1.5;
}

.violation-list{
 margin:0 0 20px 20px;
 padding:0;
 color:#101828;
 line-height:1.6;
}

.agreement-row{
 display:flex;
 align-items:flex-start;
 gap:10px;
 margin-bottom:20px;
 color:#101828;
 font-weight:600;
}

.agreement-row input{
 width:auto;
 margin:2px 0 0;
}

.modal-actions{
 display:flex;
 justify-content:flex-end;
 gap:12px;
}

/* exam page */

.exam-container{
 width:90%;
 min-height:calc(100vh - 48px);
 height:auto;
 display:flex;
 flex-direction:column;
 align-items:stretch;
 gap:18px;
 margin:0 auto;
 padding:0 0 220px;
}

.top-bar{
 width:100%;
 display:flex;
 justify-content:space-between;
 align-items:center;
 padding:18px 20px;
 position:sticky;
 top:12px;
 z-index:900;
 background:linear-gradient(135deg, #0f1728 0%, #172b4d 55%, #0b3b8c 100%);
 color:white;
 border-radius:18px;
 box-shadow:var(--shadow-soft);
}

.exam-top-right{
 display:flex;
 flex-direction:column;
 align-items:flex-end;
 gap:6px;
 font-weight:600;
}

.warning-progress{
 display:inline-flex;
 align-items:center;
 gap:4px;
 padding:6px 10px;
 border-radius:999px;
 border:1px solid transparent;
 transition:background-color 0.2s ease, color 0.2s ease, border-color 0.2s ease;
}

.warning-progress-total{
 opacity:0.92;
}

.warning-progress-safe{
 background:rgba(18, 183, 106, 0.16);
 color:#d1fadf;
 border-color:rgba(18, 183, 106, 0.35);
}

.warning-progress-warning{
 background:rgba(245, 154, 35, 0.18);
 color:#fef0c7;
 border-color:rgba(245, 154, 35, 0.35);
}

.warning-progress-danger{
 background:rgba(240, 68, 56, 0.2);
 color:#fee4e2;
 border-color:rgba(240, 68, 56, 0.4);
}

.exam-meta{
 display:flex;
 gap:12px;
 margin-top:6px;
 font-size:14px;
 color:#d5d7da;
}

.exam-actions{
 width:100%;
 display:flex;
 justify-content:flex-end;
 gap:12px;
}

.live-warning-banner{
 width:100%;
 display:grid;
 grid-template-columns:minmax(0, 1.6fr) auto;
 gap:18px;
 padding:18px 20px;
 border-radius:18px;
 border:1px solid var(--border-soft);
 background:linear-gradient(180deg, rgba(255,255,255,0.95) 0%, rgba(248,250,252,0.98) 100%);
 box-shadow:var(--shadow-soft);
 transition:border-color 0.2s ease, box-shadow 0.2s ease, background 0.2s ease;
}

.live-warning-banner-idle{
 border-color:var(--success-border);
 background:linear-gradient(180deg, #f8fff9 0%, #eefbf3 100%);
}

.live-warning-banner-warning{
 border-color:var(--warning-border);
 background:linear-gradient(180deg, #fffdf6 0%, #fff6dd 100%);
}

.live-warning-banner-error{
 border-color:var(--danger-border);
 background:linear-gradient(180deg, #fff8f8 0%, #fef0ef 100%);
}

.live-warning-banner-main{
 min-width:0;
}

.live-warning-banner-label-row{
 display:flex;
 align-items:center;
 gap:10px;
 margin-bottom:10px;
}

.live-warning-banner-kicker{
 display:inline-flex;
 align-items:center;
 padding:5px 10px;
 border-radius:999px;
 background:rgba(23, 92, 211, 0.08);
 color:var(--brand);
 font-size:12px;
 font-weight:800;
 letter-spacing:0.04em;
 text-transform:uppercase;
}

.live-warning-badge{
 display:inline-flex;
 align-items:center;
 justify-content:center;
 padding:5px 10px;
 border-radius:999px;
 font-size:12px;
 font-weight:700;
 border:1px solid transparent;
}

.live-warning-badge-idle{
 background:var(--success-soft);
 color:var(--success);
 border-color:var(--success-border);
}

.live-warning-badge-warning{
 background:var(--warning-soft);
 color:var(--warning);
 border-color:var(--warning-border);
}

.live-warning-badge-error{
 background:var(--danger-soft);
 color:var(--danger);
 border-color:var(--danger-border);
}

.live-warning-banner-title{
 margin:0;
 color:var(--text-strong);
 font-size:24px;
 line-height:1.15;
}

.live-warning-banner-text{
 margin:8px 0 0;
 color:var(--text-body);
 font-size:14px;
 line-height:1.5;
 max-width:70ch;
}

.live-warning-banner-side{
 display:grid;
 grid-template-columns:repeat(auto-fit, minmax(110px, 1fr));
 gap:10px;
 align-self:start;
}

.live-warning-metric{
 display:flex;
 flex-direction:column;
 gap:6px;
 padding:12px 14px;
 border-radius:14px;
 background:rgba(255,255,255,0.72);
 border:1px solid rgba(152, 162, 179, 0.32);
 min-width:0;
}

.live-warning-metric-label{
 color:var(--text-muted);
 font-size:11px;
 font-weight:700;
 text-transform:uppercase;
 letter-spacing:0.05em;
}

.live-warning-metric-value{
 color:var(--text-strong);
 font-size:18px;
 font-weight:800;
}

.live-warning-banner-list{
 grid-column:1 / -1;
 display:flex;
 flex-wrap:wrap;
 gap:10px;
}

.live-warning-banner-pill{
 display:inline-flex;
 align-items:center;
 max-width:100%;
 padding:8px 12px;
 border-radius:999px;
 font-size:13px;
 font-weight:700;
}

.live-warning-banner-pill-neutral{
 background:#eef2f6;
 color:#344054;
}

.live-warning-banner-pill-warning{
 background:var(--warning-soft);
 color:var(--warning);
}

.live-warning-banner-pill-error{
 background:var(--danger-soft);
 color:var(--danger);
}

.dev-monitoring-panel{
 width:100%;
 background:#fff4e5;
 border:1px solid #f5c27a;
 color:#7a2e0b;
 border-radius:16px;
 padding:14px 16px;
}

.dev-monitoring-title{
 font-weight:700;
 margin-bottom:6px;
}

.dev-monitoring-toggle{
 display:flex;
 align-items:center;
 gap:10px;
 font-weight:600;
}

.dev-monitoring-toggle input{
 width:auto;
 margin:0;
}

.dev-monitoring-message{
 margin:10px 0 0;
 font-size:14px;
}

.exam-layout{
 width:100%;
 display:flex;
 flex-direction:column;
 gap:18px;
}

.exam-support-grid{
 display:grid;
 grid-template-columns:repeat(2, minmax(0, 1fr));
 gap:18px;
}

.exam-surface{
 background:var(--bg-panel);
 border:1px solid var(--border-soft);
 border-radius:18px;
 padding:18px;
 box-shadow:var(--shadow-soft);
}

.exam-paper-surface{
 min-height:100%;
}

.section-heading-row{
 display:flex;
 justify-content:space-between;
 align-items:flex-start;
 gap:16px;
 margin-bottom:14px;
}

.section-title{
 margin:0;
 color:var(--text-strong);
 font-size:20px;
}

.section-copy{
 margin:8px 0 0;
 color:var(--text-muted);
 font-size:14px;
 line-height:1.5;
}

.question-frame{
 width:100%;
 height:calc(100vh - 240px);
 min-height:680px;
 border:none;
 border-radius:14px;
 background:#f2f4f7;
}

.summary-list{
 list-style:none;
 margin:0;
 padding:0;
 display:flex;
 flex-direction:column;
 gap:12px;
}

.empty-list-message{
 color:#475467;
 font-size:14px;
}

.summary-card{
 padding:12px;
 border:1px solid #eaecf0;
 border-radius:12px;
 background:#f8fafc;
}

.summary-card-meta{
 font-size:13px;
 color:#475467;
 margin-bottom:6px;
}

.summary-card-title{
 font-weight:700;
 color:#101828;
 margin-bottom:4px;
}

.summary-card-detail{
 font-size:14px;
 color:#344054;
 line-height:1.4;
}

.summary-option-list{
 margin:0;
 padding-left:18px;
 display:flex;
 flex-direction:column;
 gap:6px;
}

.exam-side-card{
 background:#ffffff;
 border:1px solid #d0d5dd;
 border-radius:18px;
 padding:18px;
}

.video-box{
 position:relative;
 width:100%;
 display:flex;
 flex-direction:column;
 gap:14px;
 color:#101828;
 transition:border-color 0.2s ease, box-shadow 0.2s ease, transform 0.2s ease, background-color 0.2s ease;
}

.video-box-idle{
 border-color:#d0d5dd;
}

.video-box-monitoring{
 border-color:#98a2b3;
 box-shadow:0 8px 24px rgba(15, 23, 42, 0.08);
}

.video-box-warning{
 border-color:#98a2b3;
 box-shadow:0 8px 24px rgba(15, 23, 42, 0.08);
}

.video-box-error{
 border-color:#98a2b3;
 background:rgba(255, 255, 255, 0.96);
 box-shadow:0 8px 24px rgba(15, 23, 42, 0.08);
}

.proctor-panel{
 align-self:stretch;
 width:100%;
 padding:12px;
 border-radius:18px;
 background:rgba(255, 255, 255, 0.96);
 backdrop-filter:blur(14px);
}

.proctor-panel-header{
 display:flex;
 justify-content:space-between;
 align-items:center;
 gap:10px;
}

.proctor-panel-title{
 margin:0;
 font-size:16px;
 font-weight:700;
 color:#101828;
}

.proctor-panel-kicker{
 margin-bottom:4px;
 color:var(--brand);
 font-size:11px;
 font-weight:800;
 letter-spacing:0.05em;
 text-transform:uppercase;
}

.proctor-panel-handle{
 cursor:move;
 user-select:none;
}

.proctor-panel-actions{
 display:flex;
 align-items:center;
  gap:8px;
}

.proctor-dock{
 position:fixed;
 right:24px;
 bottom:24px;
 width:min(310px, calc(100vw - 24px));
 z-index:1200;
}

.proctor-dock.is-dragging{
 opacity:0.96;
 box-shadow:0 24px 60px rgba(15, 23, 42, 0.28);
}

.proctor-dock-body{
 display:flex;
 flex-direction:column;
 gap:10px;
}

.proctor-dock-toggle{
 background:#101828;
 color:#fff;
 border:none;
 border-radius:999px;
 padding:8px 12px;
 font-size:12px;
 font-weight:700;
 white-space:nowrap;
}

.proctor-dock-toggle:hover{
 background:#1d2939;
}

.proctor-dock.is-collapsed{
 width:min(220px, calc(100vw - 24px));
}

.proctor-dock.is-collapsed .proctor-dock-body{
 display:none;
}

.video-status-badge{
 display:inline-flex;
 align-items:center;
 justify-content:center;
 min-width:72px;
 padding:6px 10px;
 border-radius:999px;
 font-size:11px;
 font-weight:700;
 letter-spacing:0.02em;
 text-transform:uppercase;
 border:1px solid transparent;
}

.video-status-badge-idle{
 background:#f2f4f7;
 color:#344054;
 border-color:#d0d5dd;
}

.video-status-badge-monitoring{
 background:#eff8ff;
 color:#175cd3;
 border-color:#b2ddff;
}

.video-status-badge-warning{
 background:#fffaeb;
 color:#b54708;
 border-color:#fedf89;
}

.video-status-badge-error{
 background:#fef3f2;
 color:#b42318;
 border-color:#fecdca;
}

.video-frame{
  position:relative;
  border-radius:12px;
  overflow:hidden;
  background:#101828;
  border:1px solid #d0d5dd;
}

video{
 width:100%;
 aspect-ratio:4 / 3;
 height:auto;
 object-fit:cover;
 display:block;
}

.proctor-status-strip{
 display:flex;
 flex-wrap:wrap;
 gap:6px;
}

.proctor-status-chip{
 display:inline-flex;
 align-items:center;
 padding:6px 10px;
 border-radius:999px;
 background:#f8fafc;
 border:1px solid #eaecf0;
 color:#344054;
 font-size:12px;
 font-weight:700;
}

.proctor-status-copy{
 margin:0;
 font-size:13px;
 line-height:1.4;
  color:#475467;
}

.video-warning-stack{
 display:flex;
 flex-wrap:wrap;
 gap:8px;
}

.video-warning-pill{
 display:inline-flex;
 align-items:center;
 max-width:100%;
 padding:6px 9px;
  border-radius:999px;
 font-size:11px;
  font-weight:600;
  line-height:1.2;
}

.video-warning-pill-neutral{
 background:#f2f4f7;
 color:#344054;
}

.video-warning-pill-warning{
 background:#f2f4f7;
 color:#344054;
}

.video-warning-pill-info{
 background:#f2f4f7;
 color:#344054;
}

.secondary-btn{
 background:#475467;
}

.secondary-btn:hover{
 background:#344054;
}

.primary-btn{
 background:#c4320a;
}

.primary-btn:hover{
 background:#9c2a10;
}

.completion-screen{
 display:flex;
 justify-content:center;
 align-items:center;
 height:100vh;
 width:100%;
 background:#f4f6f9;
}

.completion-card{
 background:white;
 padding:40px;
 border-radius:12px;
 box-shadow:0 4px 10px rgba(0,0,0,0.1);
 text-align:center;
}

@media (max-width: 900px){
 body{
  display:block;
  height:auto;
  min-height:100vh;
  padding:24px 0;
 }

 .container{
  width:min(92vw, 520px);
  padding:28px 20px;
  margin:0 auto;
 }

 .dashboard-header{
  flex-direction:column;
  align-items:stretch;
 }

 .modal-card{
  padding:22px;
 }

 .exam-container{
  width:min(94vw, 100%);
  padding-bottom:240px;
 }

 .top-bar{
  flex-direction:column;
  align-items:flex-start;
  gap:12px;
 }

 .exam-top-right{
  width:100%;
  align-items:flex-start;
 }

 .exam-meta{
  flex-direction:column;
  gap:4px;
 }

 .exam-actions{
  flex-wrap:wrap;
  justify-content:stretch;
 }

 .exam-actions button{
  flex:1 1 220px;
 }

 .live-warning-banner{
  grid-template-columns:1fr;
 }

 .live-warning-banner-side{
  grid-template-columns:repeat(auto-fit, minmax(120px, 1fr));
 }

 .exam-layout{
  gap:16px;
 }

 .exam-support-grid{
  grid-template-columns:1fr;
 }

 .question-frame{
  height:540px;
  min-height:540px;
 }

 .proctor-dock{
  right:16px;
  bottom:16px;
 }
}

@media (max-width: 640px){
 body.exam-page{
  padding:16px 0;
 }

 .container{
  width:min(94vw, 100%);
  padding:24px 16px;
  border-radius:12px;
 }

 .status-message{
  width:100%;
 }

 .dashboard-card{
  padding:16px;
  margin:12px 0 18px;
 }

 .modal-overlay{
  padding:16px;
 }

 .modal-card{
  padding:18px;
 }

 .modal-actions{
  flex-direction:column;
 }

 .modal-actions button{
  width:100%;
 }

 .exam-container{
  gap:12px;
  padding-bottom:260px;
 }

 .top-bar{
  padding:12px;
 }

 .warning-progress{
  flex-wrap:wrap;
  border-radius:16px;
 }

 .video-box{
  width:100%;
  }

 .live-warning-banner{
  padding:16px;
  border-radius:16px;
 }

 .live-warning-banner-title{
  font-size:20px;
 }

 .live-warning-banner-side{
  grid-template-columns:1fr;
 }

 .exam-surface,
 .exam-side-card{
  padding:16px;
  border-radius:16px;
 }

 .question-frame{
  height:420px;
  min-height:420px;
 }

 .proctor-panel-header{
  flex-direction:column;
  align-items:flex-start;
 }

 .proctor-status-grid{
  grid-template-columns:1fr 1fr;
 }

 .proctor-dock{
  right:12px;
  bottom:12px;
  width:min(320px, calc(100vw - 24px));
 }

 .proctor-dock.is-collapsed{
  width:min(240px, calc(100vw - 24px));
 }

 .completion-card{
  width:min(92vw, 100%);
  padding:28px 20px;
 }
}

