  }

  registerDevMonitoringControls()
  await loadDevMonitoringSettings()
  registerExamGuards()
  registerAudioUnlockHandlers()
  await unlockAlertAudio()

  if (window.electronAPI?.startFullscreen) {
    window.electronAPI.startFullscreen()
  }

  await loadExam()
})

