// ============================================================================
// Simple Backend Server for Room Enrollment Testing
// No WebRTC/mediasoup dependency - Express + in-memory storage
// ============================================================================

const express = require('express');
const cors = require('cors');
const crypto = require('crypto');

const app = express();
const PORT = 5000;

// Middleware
app.use(cors());
app.use(express.json());

// ============================================================================
// In-Memory Data Storage
// ============================================================================

const rooms = new Map();
const roomEnrollments = new Map(); // roomId -> Set of student emails
const users = new Map();

// Seed data
function seedDatabase() {
  // Create test teacher
  const teacherId = 1;
  users.set('teacher@school.edu', {
    id: teacherId,
    email: 'teacher@school.edu',
    name: 'Dr. Smith',
    role: 'teacher'
  });

  // Create test exam
  const examId = 1;

  // Create test room with invite code
  const roomCode = 'MTH101AB';
  const roomId = 2;
  rooms.set(roomCode, {
    id: roomId,
    room_code: roomCode,
    exam_id: examId,
    teacher_id: teacherId,
    status: 'created',
    capacity: 15,
    exam_name: 'Midterm Mathematics',
    course_name: 'MATH 101',
    created_at: new Date().toISOString()
  });

  roomEnrollments.set(roomId, new Set());

  console.log('✅ Database seeded with test data');
  console.log(`   Room: ${roomCode} (MATH 101 - Midterm Mathematics)`);
}

seedDatabase();

// ============================================================================
// Helper Functions
// ============================================================================

function generateRoomCode() {
  const chars = '0123456789abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ';
  let code = '';
  for (let i = 0; i < 8; i++) {
    code += chars.charAt(Math.floor(Math.random() * chars.length));
  }
  return code;
}

// ============================================================================
// API Routes
// ============================================================================

// Health check
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

// POST /api/room/create - Create a new proctoring room
app.post('/api/room/create', (req, res) => {
  const { examId } = req.body;

  if (!examId) {
    return res.status(400).json({
      success: false,
      error: 'examId is required'
    });
  }

  const roomCode = generateRoomCode();
  const room = {
    id: rooms.size + 1,
    room_code: roomCode,
    exam_id: examId,
    teacher_id: 1,
    status: 'created',
    capacity: 15,
    exam_name: 'Test Exam',
    course_name: 'Test Course',
    created_at: new Date().toISOString()
  };

  rooms.set(roomCode, room);
  roomEnrollments.set(room.id, new Set());

  console.log(`✅ Room created: ${roomCode}`);

  res.json({
    success: true,
    data: {
      roomId: room.id,
      roomCode: room.room_code,
      inviteLink: `proctor://room/${room.room_code}`,
      examName: room.exam_name,
      courseName: room.course_name
    }
  });
});

// GET /api/room/:code - Get room by code
app.get('/api/room/:code', (req, res) => {
  const { code } = req.params;
  const room = rooms.get(code);

  if (!room) {
    return res.status(404).json({
      success: false,
      error: 'Invalid invite link'
    });
  }

  res.json({
    success: true,
    data: {
      roomId: room.id,
      examName: room.exam_name,
      courseName: room.course_name,
      status: room.status
    }
  });
});

// POST /api/room/:code/join - Student joins a room
app.post('/api/room/:code/join', (req, res) => {
  const { code } = req.params;
  const { studentName, studentEmail } = req.body;

  // Validate inputs
  if (!studentName || !studentEmail) {
    return res.status(400).json({
      success: false,
      error: 'studentName and studentEmail are required'
    });
  }

  // Email validation
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (!emailRegex.test(studentEmail)) {
    return res.status(400).json({
      success: false,
      error: 'Invalid email address'
    });
  }

  // Get room
  const room = rooms.get(code);
  if (!room) {
    return res.status(404).json({
      success: false,
      error: 'Invalid invite code'
    });
  }

  // Get or create user
  let user = users.get(studentEmail);
  if (!user) {
    user = {
      id: users.size + 1,
      email: studentEmail,
      name: studentName,
      role: 'student'
    };
    users.set(studentEmail, user);
    console.log(`✅ User created: ${studentEmail}`);
  }

  // Check enrollment
  const enrollments = roomEnrollments.get(room.id);
  if (enrollments.has(studentEmail)) {
    return res.status(409).json({
      success: false,
      error: `Email ${studentEmail} is already enrolled in room ${code}`
    });
  }

  // Check capacity
  if (enrollments.size >= room.capacity) {
    return res.status(429).json({
      success: false,
      error: `Room ${code} is full (${enrollments.size}/${room.capacity} students)`
    });
  }

  // Enroll student
  const enrollmentId = Date.now();
  enrollments.add(studentEmail);

  console.log(`✅ Student enrolled: ${studentName} (${studentEmail}) -> Room ${code}`);
  console.log(`   Room capacity: ${enrollments.size}/${room.capacity}`);

  res.json({
    success: true,
    data: {
      enrollmentId: enrollmentId,
      roomId: room.id,
      roomCode: room.room_code,
      examName: room.exam_name,
      courseName: room.course_name,
      status: room.status
    }
  });
});

// GET /api/room/:code/students - Get enrolled students (for teacher dashboard)
app.get('/api/room/:code/students', (req, res) => {
  const { code } = req.params;
  const room = rooms.get(code);

  if (!room) {
    return res.status(404).json({
      success: false,
      error: 'Room not found'
    });
  }

  const enrollments = roomEnrollments.get(room.id);
  const students = Array.from(enrollments).map(email => {
    const user = users.get(email);
    return {
      name: user?.name || 'Unknown',
      email: email,
      joinedAt: new Date().toISOString()
    };
  });

  res.json({
    success: true,
    data: {
      roomId: room.id,
      roomCode: room.room_code,
      studentCount: students.length,
      capacity: room.capacity,
      students: students
    }
  });
});

// ============================================================================
// Start Server
// ============================================================================

app.listen(PORT, () => {
  console.log('');
  console.log('╔════════════════════════════════════════════════════════════╗');
  console.log('║  Moodle Proctor - Room Enrollment Server                ║');
  console.log('╚════════════════════════════════════════════════════════════╝');
  console.log('');
  console.log(`🚀 Server running on http://localhost:${PORT}`);
  console.log(`📚 Health check: http://localhost:${PORT}/health`);
  console.log('');
  console.log('📝 Available Endpoints:');
  console.log('   POST /api/room/create              - Create room');
  console.log('   GET  /api/room/:code               - Get room info');
  console.log('   POST /api/room/:code/join          - Student joins room');
  console.log('   GET  /api/room/:code/students      - Get enrolled students');
  console.log('');
  console.log('🎯 Demo Credentials:');
  console.log('   Room Code: MTH101AB');
  console.log('   Exam: MATH 101 - Midterm Mathematics');
  console.log('   Capacity: 15 students');
  console.log('');
  console.log('✅ Ready for testing!');
  console.log('═════════════════════════════════════════════════════════════');
  console.log('');
});

